{
  "name": "Naija Legal Buddy",
  "description": "A personal legal assistant providing clear, simplified guidance for everyday Nigerian legal situations, from police stops to landlord disputes.",
  "requestFramePermissions": [
    "microphone"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum Category {
  TRAFFIC = 'Traffic / Police Stops',
  LANDLORD = 'Landlord / Tenant Issues',
  WORKPLACE = 'Workplace & Salary Rights',
  CONSUMER = 'Consumer Rights / Fraud',
  DOMESTIC = 'Domestic Disputes',
  EMERGENCY = 'Emergency Situations'
}

export interface LegalAdvice {
  explanation: string;
  steps: string[];
  laws: { title: string; section: string; link?: string }[];
  templates?: { name: string; content: string }[];
  contacts?: { name: string; info: string }[];
  groundingUrls?: string[];
}

export interface ClarificationQuestion {
  question: string;
  options: string[];
}

export interface SavedCase {
  id: string;
  title: string;
  timestamp: number;
  advice: LegalAdvice;
  status: 'pending' | 'resolved' | 'sent';
}

export interface AppState {
  currentView: 'home' | 'interaction' | 'tracker' | 'glossary' | 'emergency';
  history: string[];
  isSearching: boolean;
}

import React from 'react';
import { ShieldAlert, Home, Briefcase, ShoppingCart, Users, Siren, Scale, BookOpen } from 'lucide-react';
import { Category } from './types';

export const CATEGORIES = [
  { id: 'traffic', name: Category.TRAFFIC, icon: <ShieldAlert className="w-6 h-6" />, color: 'bg-blue-100 text-blue-700' },
  { id: 'landlord', name: Category.LANDLORD, icon: <Home className="w-6 h-6" />, color: 'bg-green-100 text-green-700' },
  { id: 'workplace', name: Category.WORKPLACE, icon: <Briefcase className="w-6 h-6" />, color: 'bg-purple-100 text-purple-700' },
  { id: 'consumer', name: Category.CONSUMER, icon: <ShoppingCart className="w-6 h-6" />, color: 'bg-orange-100 text-orange-700' },
  { id: 'domestic', name: Category.DOMESTIC, icon: <Users className="w-6 h-6" />, color: 'bg-pink-100 text-pink-700' },
  { id: 'emergency', name: Category.EMERGENCY, icon: <Siren className="w-6 h-6" />, color: 'bg-red-100 text-red-700' },
];

export const GLOSSARY = [
  { term: 'Eviction Notice', definition: 'A formal letter from a landlord asking a tenant to move out within a specified legal timeframe.' },
  { term: 'Warrant', definition: 'A legal document issued by a judge or magistrate authorizing the police to perform a specified act, like a search or arrest.' },
  { term: 'Consumer Protection Council (CPC)', definition: 'The Nigerian agency responsible for protecting consumers from unfair trade practices.' },
  { term: 'Small Claims Court', definition: 'A special judicial process for resolving minor financial disputes quickly and without complex legal fees.' },
  { term: 'Tenancy Agreement', definition: 'A contract between a landlord and a tenant that outlines the rights and responsibilities of both parties.' },
];

import { GoogleGenAI, Type } from "@google/genai";
import { LegalAdvice, ClarificationQuestion } from '../types';

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const SYSTEM_INSTRUCTION = `
You are Naija Legal Buddy, a world-class legal assistant for Nigeria. 
Your goal is to provide clear, simplified, and practical legal guidance based on Nigerian Law.
You must:
1. Use Nigerian legal frameworks (Constitution, Tenancy Laws, Police Act, Labour Act, etc.).
2. Speak clearly, avoiding complex jargon where possible, or explaining it.
3. Be culturally aware of Nigeria (Pidgin is acceptable for context, but keep advice professional).
4. Always provide specific steps a person can take.
5. Use Google Search grounding to ensure you have the most up-to-date information on Nigerian regulations.
`;

export const analyzeSituation = async (situation: string, history: string[] = []): Promise<{
  needsClarification?: ClarificationQuestion;
  advice?: LegalAdvice;
}> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [
        { role: 'user', parts: [{ text: `Situation: ${situation}\nPrevious Context: ${history.join('\n')}` }] }
      ],
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        tools: [{ googleSearch: {} }],
        responseMimeType: 'application/json',
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            needsClarification: {
              type: Type.OBJECT,
              properties: {
                question: { type: Type.STRING },
                options: { type: Type.ARRAY, items: { type: Type.STRING } }
              },
              required: ['question', 'options']
            },
            advice: {
              type: Type.OBJECT,
              properties: {
                explanation: { type: Type.STRING },
                steps: { type: Type.ARRAY, items: { type: Type.STRING } },
                laws: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      title: { type: Type.STRING },
                      section: { type: Type.STRING },
                      link: { type: Type.STRING }
                    },
                    required: ['title', 'section']
                  }
                },
                templates: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      name: { type: Type.STRING },
                      content: { type: Type.STRING }
                    }
                  }
                },
                contacts: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      name: { type: Type.STRING },
                      info: { type: Type.STRING }
                    }
                  }
                }
              }
            }
          }
        }
      }
    });

    const result = JSON.parse(response.text);

    // Add grounding URLs if available
    if (result.advice && response.candidates?.[0]?.groundingMetadata?.groundingChunks) {
      const urls = response.candidates[0].groundingMetadata.groundingChunks
        .map(chunk => chunk.web?.uri)
        .filter((url): url is string => !!url);
      result.advice.groundingUrls = Array.from(new Set(urls));
    }

    return result;
  } catch (error) {
    console.error("Error analyzing situation:", error);
    throw error;
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { Shield, Search, Mic, Home as HomeIcon, BookOpen, Clock, AlertTriangle, Menu, X, ArrowLeft, Send, CheckCircle, ExternalLink } from 'lucide-react';
import { AppState, SavedCase, LegalAdvice, Category, ClarificationQuestion } from './types';
import { CATEGORIES, GLOSSARY } from './constants';
import { analyzeSituation } from './services/geminiService';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>({
    currentView: 'home',
    history: [],
    isSearching: false
  });
  const [input, setInput] = useState('');
  const [advice, setAdvice] = useState<LegalAdvice | null>(null);
  const [clarification, setClarification] = useState<ClarificationQuestion | null>(null);
  const [savedCases, setSavedCases] = useState<SavedCase[]>([]);
  const [isRecording, setIsRecording] = useState(false);
  const [isMenuOpen, setIsMenuOpen] = useState(false);

  // Load saved cases from localStorage
  useEffect(() => {
    const stored = localStorage.getItem('naija_legal_cases');
    if (stored) {
      setSavedCases(JSON.parse(stored));
    }
  }, []);

  const saveCase = (advice: LegalAdvice, title: string) => {
    const newCase: SavedCase = {
      id: Date.now().toString(),
      title,
      timestamp: Date.now(),
      advice,
      status: 'pending'
    };
    const updated = [newCase, ...savedCases];
    setSavedCases(updated);
    localStorage.setItem('naija_legal_cases', JSON.stringify(updated));
    alert('Case saved to your tracker!');
  };

  const handleSearch = async (query: string = input) => {
    if (!query.trim()) return;
    setState(prev => ({ ...prev, isSearching: true, currentView: 'interaction' }));
    setAdvice(null);
    setClarification(null);

    try {
      const result = await analyzeSituation(query, state.history);
      if (result.needsClarification) {
        setClarification(result.needsClarification);
      } else if (result.advice) {
        setAdvice(result.advice);
      }
      setState(prev => ({ ...prev, history: [...prev.history, query], isSearching: false }));
    } catch (err) {
      alert("Something went wrong. Please check your internet connection.");
      setState(prev => ({ ...prev, isSearching: false, currentView: 'home' }));
    }
  };

  const handleClarification = (option: string) => {
    handleSearch(`${clarification?.question}: ${option}`);
  };

  const handleVoice = () => {
    if (!('webkitSpeechRecognition' in window)) {
      alert("Speech recognition not supported in this browser.");
      return;
    }
    const recognition = new (window as any).webkitSpeechRecognition();
    recognition.lang = 'en-NG';
    recognition.onstart = () => setIsRecording(true);
    recognition.onresult = (event: any) => {
      const transcript = event.results[0][0].transcript;
      setInput(transcript);
      handleSearch(transcript);
    };
    recognition.onend = () => setIsRecording(false);
    recognition.start();
  };

  const renderHome = () => (
    <div className="max-w-2xl mx-auto px-4 py-8">
      <div className="text-center mb-10">
        <h1 className="text-3xl font-bold text-slate-800 mb-2">How can I help you today?</h1>
        <p className="text-slate-500">Get clear legal guidance on Nigerian laws in seconds.</p>
      </div>

      <div className="relative mb-8 group">
        <div className="absolute inset-y-0 left-4 flex items-center pointer-events-none">
          <Search className="w-5 h-5 text-slate-400" />
        </div>
        <input
          type="text"
          value={input}
          onChange={(e) => setInput(e.target.value)}
          placeholder="Type your situation (e.g. My landlord cut my light)"
          className="w-full pl-12 pr-12 py-4 bg-white border border-slate-200 rounded-2xl shadow-sm focus:ring-2 focus:ring-emerald-500 focus:border-transparent outline-none transition-all"
          onKeyDown={(e) => e.key === 'Enter' && handleSearch()}
        />
        <button 
          onClick={handleVoice}
          className={`absolute inset-y-0 right-4 flex items-center transition-colors ${isRecording ? 'text-red-500 animate-pulse' : 'text-slate-400 hover:text-emerald-500'}`}
        >
          <Mic className="w-5 h-5" />
        </button>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-3 gap-4 mb-10">
        {CATEGORIES.map((cat) => (
          <button
            key={cat.id}
            onClick={() => handleSearch(cat.name)}
            className="flex flex-col items-center justify-center p-4 bg-white border border-slate-100 rounded-2xl shadow-sm hover:shadow-md hover:border-emerald-200 transition-all group"
          >
            <div className={`p-3 rounded-full mb-3 ${cat.color} group-hover:scale-110 transition-transform`}>
              {cat.icon}
            </div>
            <span className="text-xs font-semibold text-slate-700 text-center">{cat.name}</span>
          </button>
        ))}
      </div>

      <div className="bg-emerald-50 rounded-2xl p-6 border border-emerald-100 flex items-start gap-4">
        <div className="bg-emerald-500 p-2 rounded-lg text-white">
          <AlertTriangle className="w-5 h-5" />
        </div>
        <div>
          <h3 className="font-semibold text-emerald-900 mb-1 text-sm">Emergency?</h3>
          <p className="text-emerald-700 text-xs leading-relaxed">
            If you are currently being detained or facing immediate danger, tap Emergency Mode for instant safety steps.
          </p>
          <button 
            onClick={() => setState({ ...state, currentView: 'emergency' })}
            className="mt-2 text-emerald-800 font-bold text-xs uppercase tracking-wider"
          >
            Go to Emergency Mode &rarr;
          </button>
        </div>
      </div>
    </div>
  );

  const renderInteraction = () => (
    <div className="max-w-2xl mx-auto px-4 py-8">
      <button 
        onClick={() => setState({ ...state, currentView: 'home' })}
        className="flex items-center text-slate-500 hover:text-slate-800 mb-6 transition-colors"
      >
        <ArrowLeft className="w-4 h-4 mr-2" /> Back
      </button>

      {state.isSearching ? (
        <div className="flex flex-col items-center justify-center py-20 space-y-4">
          <div className="w-12 h-12 border-4 border-emerald-500 border-t-transparent rounded-full animate-spin"></div>
          <p className="text-slate-600 font-medium animate-pulse text-center">
            Reviewing Nigerian Law Books... <br/>
            <span className="text-xs text-slate-400">Verifying the most current regulations</span>
          </p>
        </div>
      ) : clarification ? (
        <div className="bg-white rounded-2xl p-8 shadow-sm border border-slate-100 animate-in slide-in-from-bottom-4 duration-300">
          <h2 className="text-xl font-bold text-slate-800 mb-6">{clarification.question}</h2>
          <div className="space-y-3">
            {clarification.options.map((option, idx) => (
              <button
                key={idx}
                onClick={() => handleClarification(option)}
                className="w-full text-left p-4 rounded-xl border border-slate-200 hover:border-emerald-500 hover:bg-emerald-50 transition-all font-medium text-slate-700"
              >
                {option}
              </button>
            ))}
          </div>
        </div>
      ) : advice ? (
        <div className="space-y-6 pb-20 animate-in fade-in duration-500">
          <div className="bg-emerald-600 text-white rounded-2xl p-6 shadow-lg">
            <h2 className="text-lg font-bold mb-3 flex items-center">
              <CheckCircle className="w-5 h-5 mr-2" />
              Here's the Guidance
            </h2>
            <p className="text-emerald-50 leading-relaxed text-sm">
              {advice.explanation}
            </p>
          </div>

          <div className="bg-white rounded-2xl p-6 border border-slate-200 shadow-sm">
            <h3 className="font-bold text-slate-800 mb-4 flex items-center">
              <Clock className="w-4 h-4 mr-2 text-blue-500" />
              Steps You Should Take
            </h3>
            <ul className="space-y-4">
              {advice.steps.map((step, i) => (
                <li key={i} className="flex gap-4">
                  <div className="flex-shrink-0 w-6 h-6 rounded-full bg-slate-100 text-slate-600 text-xs flex items-center justify-center font-bold">
                    {i + 1}
                  </div>
                  <span className="text-slate-600 text-sm">{step}</span>
                </li>
              ))}
            </ul>
          </div>

          <div className="bg-white rounded-2xl p-6 border border-slate-200 shadow-sm">
            <h3 className="font-bold text-slate-800 mb-4 flex items-center">
              <Scale className="w-4 h-4 mr-2 text-indigo-500" />
              Legal References (Nigeria)
            </h3>
            <div className="space-y-3">
              {advice.laws.map((law, i) => (
                <div key={i} className="p-3 bg-slate-50 rounded-xl border border-slate-100">
                  <p className="font-semibold text-slate-800 text-sm">{law.title}</p>
                  <p className="text-xs text-slate-500">{law.section}</p>
                </div>
              ))}
            </div>
          </div>

          {advice.templates && advice.templates.length > 0 && (
            <div className="bg-white rounded-2xl p-6 border border-slate-200 shadow-sm">
              <h3 className="font-bold text-slate-800 mb-4 flex items-center">
                <Send className="w-4 h-4 mr-2 text-emerald-500" />
                Templates & Forms
              </h3>
              <div className="space-y-3">
                {advice.templates.map((tmpl, i) => (
                  <button 
                    key={i}
                    onClick={() => {
                      navigator.clipboard.writeText(tmpl.content);
                      alert('Template copied to clipboard!');
                    }}
                    className="w-full text-left p-3 rounded-xl bg-emerald-50 text-emerald-700 border border-emerald-100 flex items-center justify-between hover:bg-emerald-100 transition-all"
                  >
                    <span className="text-sm font-medium">{tmpl.name}</span>
                    <span className="text-[10px] bg-white px-2 py-1 rounded-full uppercase font-bold border border-emerald-200">Copy</span>
                  </button>
                ))}
              </div>
            </div>
          )}

          {advice.groundingUrls && advice.groundingUrls.length > 0 && (
            <div className="p-4 bg-slate-100 rounded-xl text-xs">
              <p className="text-slate-500 mb-2 font-bold uppercase tracking-tight">Verified Sources:</p>
              <div className="flex flex-wrap gap-2">
                {advice.groundingUrls.map((url, i) => (
                  <a key={i} href={url} target="_blank" rel="noopener noreferrer" className="text-emerald-600 hover:underline flex items-center gap-1">
                    Source {i + 1} <ExternalLink className="w-2 h-2" />
                  </a>
                ))}
              </div>
            </div>
          )}

          <div className="fixed bottom-6 left-0 right-0 px-4 flex gap-3 max-w-2xl mx-auto">
            <button 
              onClick={() => saveCase(advice, input || "Saved Advice")}
              className="flex-1 bg-white border border-slate-200 text-slate-700 font-bold py-3 rounded-xl shadow-lg flex items-center justify-center gap-2 hover:bg-slate-50 transition-all"
            >
              <Clock className="w-4 h-4" /> Save to Tracker
            </button>
            <button 
              onClick={() => setState({ ...state, currentView: 'home' })}
              className="bg-emerald-500 text-white font-bold py-3 px-8 rounded-xl shadow-lg hover:bg-emerald-600 transition-all"
            >
              Done
            </button>
          </div>
        </div>
      ) : null}
    </div>
  );

  const renderTracker = () => (
    <div className="max-w-2xl mx-auto px-4 py-8 pb-24">
      <h2 className="text-2xl font-bold text-slate-800 mb-6 flex items-center">
        <Clock className="w-6 h-6 mr-3 text-blue-500" /> Case Tracker
      </h2>
      {savedCases.length === 0 ? (
        <div className="text-center py-20 bg-white rounded-2xl border border-dashed border-slate-200">
          <p className="text-slate-400">No saved cases yet.</p>
        </div>
      ) : (
        <div className="space-y-4">
          {savedCases.map((c) => (
            <div key={c.id} className="bg-white p-5 rounded-2xl border border-slate-200 shadow-sm hover:border-emerald-200 transition-all">
              <div className="flex justify-between items-start mb-2">
                <h3 className="font-bold text-slate-800">{c.title}</h3>
                <span className={`text-[10px] px-2 py-1 rounded-full uppercase font-bold ${
                  c.status === 'resolved' ? 'bg-emerald-100 text-emerald-700' : 'bg-orange-100 text-orange-700'
                }`}>
                  {c.status}
                </span>
              </div>
              <p className="text-xs text-slate-400 mb-4">{new Date(c.timestamp).toLocaleDateString()}</p>
              <button 
                onClick={() => {
                  setAdvice(c.advice);
                  setState({ ...state, currentView: 'interaction' });
                }}
                className="text-emerald-600 text-sm font-bold hover:underline"
              >
                View Advice &rarr;
              </button>
            </div>
          ))}
        </div>
      )}
    </div>
  );

  const renderGlossary = () => (
    <div className="max-w-2xl mx-auto px-4 py-8 pb-24">
      <h2 className="text-2xl font-bold text-slate-800 mb-6 flex items-center">
        <BookOpen className="w-6 h-6 mr-3 text-indigo-500" /> Legal Glossary
      </h2>
      <div className="space-y-4">
        {GLOSSARY.map((item, i) => (
          <div key={i} className="bg-white p-5 rounded-2xl border border-slate-200 shadow-sm">
            <h3 className="font-bold text-emerald-600 mb-1">{item.term}</h3>
            <p className="text-slate-600 text-sm leading-relaxed">{item.definition}</p>
          </div>
        ))}
      </div>
    </div>
  );

  const renderEmergency = () => (
    <div className="max-w-2xl mx-auto px-4 py-8 bg-red-50 min-h-screen">
      <button 
        onClick={() => setState({ ...state, currentView: 'home' })}
        className="flex items-center text-red-600 font-bold mb-6"
      >
        <ArrowLeft className="w-4 h-4 mr-2" /> Exit Emergency Mode
      </button>

      <div className="bg-red-600 text-white rounded-2xl p-8 shadow-xl mb-6">
        <div className="flex items-center gap-4 mb-4">
          <AlertTriangle className="w-10 h-10 animate-pulse" />
          <h2 className="text-3xl font-extrabold uppercase tracking-tight">Emergency Steps</h2>
        </div>
        <p className="font-medium text-red-100 mb-6">If you are currently facing legal trouble, follow these steps immediately:</p>

        <div className="space-y-6">
          <div className="bg-red-700/50 p-4 rounded-xl">
            <h4 className="font-bold mb-1">1. Stay Calm & Compliant</h4>
            <p className="text-sm text-red-100">Do not resist physically. Maintain a respectful but firm tone.</p>
          </div>
          <div className="bg-red-700/50 p-4 rounded-xl">
            <h4 className="font-bold mb-1">2. Identify Yourself</h4>
            <p className="text-sm text-red-100">You are required to show ID. You are NOT required to give passwords to your phone without a warrant.</p>
          </div>
          <div className="bg-red-700/50 p-4 rounded-xl">
            <h4 className="font-bold mb-1">3. Record and Recall</h4>
            <p className="text-sm text-red-100">Take note of officer names, badge numbers, vehicle plates, and location if possible.</p>
          </div>
          <div className="bg-red-700/50 p-4 rounded-xl">
            <h4 className="font-bold mb-1">4. Contact Legal Aid</h4>
            <p className="text-sm text-red-100">Call the Legal Aid Council of Nigeria at +234 800 000 0000 or your family lawyer.</p>
          </div>
        </div>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-30 px-4 py-3 shadow-sm">
        <div className="max-w-2xl mx-auto flex justify-between items-center">
          <div 
            className="flex items-center gap-2 cursor-pointer"
            onClick={() => setState({ ...state, currentView: 'home' })}
          >
            <div className="bg-emerald-500 p-1.5 rounded-lg text-white">
              <Shield className="w-6 h-6" />
            </div>
            <span className="font-bold text-slate-800 tracking-tight">Naija Legal Buddy</span>
          </div>
          <button 
            onClick={() => setIsMenuOpen(!isMenuOpen)}
            className="p-2 text-slate-500 hover:bg-slate-50 rounded-lg transition-colors"
          >
            {isMenuOpen ? <X /> : <Menu />}
          </button>
        </div>
      </header>

      {/* Main Content Area */}
      <main className="flex-grow">
        {state.currentView === 'home' && renderHome()}
        {state.currentView === 'interaction' && renderInteraction()}
        {state.currentView === 'tracker' && renderTracker()}
        {state.currentView === 'glossary' && renderGlossary()}
        {state.currentView === 'emergency' && renderEmergency()}
      </main>

      {/* Side Menu Drawer */}
      {isMenuOpen && (
        <>
          <div className="fixed inset-0 bg-black/20 z-40 backdrop-blur-sm" onClick={() => setIsMenuOpen(false)}></div>
          <div className="fixed top-0 right-0 h-full w-64 bg-white z-50 shadow-2xl p-6 animate-in slide-in-from-right duration-300">
            <button onClick={() => setIsMenuOpen(false)} className="absolute top-4 right-4 text-slate-400"><X /></button>
            <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-6">Menu</h3>
            <div className="space-y-2">
              <button 
                onClick={() => { setState({ ...state, currentView: 'home' }); setIsMenuOpen(false); }}
                className="w-full flex items-center gap-3 p-3 rounded-xl hover:bg-slate-50 text-slate-700 font-medium transition-colors"
              >
                <HomeIcon className="w-5 h-5 text-emerald-500" /> Home
              </button>
              <button 
                onClick={() => { setState({ ...state, currentView: 'tracker' }); setIsMenuOpen(false); }}
                className="w-full flex items-center gap-3 p-3 rounded-xl hover:bg-slate-50 text-slate-700 font-medium transition-colors"
              >
                <Clock className="w-5 h-5 text-blue-500" /> Case Tracker
              </button>
              <button 
                onClick={() => { setState({ ...state, currentView: 'glossary' }); setIsMenuOpen(false); }}
                className="w-full flex items-center gap-3 p-3 rounded-xl hover:bg-slate-50 text-slate-700 font-medium transition-colors"
              >
                <BookOpen className="w-5 h-5 text-indigo-500" /> Legal Glossary
              </button>
              <button 
                onClick={() => { setState({ ...state, currentView: 'emergency' }); setIsMenuOpen(false); }}
                className="w-full flex items-center gap-3 p-3 rounded-xl hover:bg-red-50 text-red-600 font-bold transition-colors"
              >
                <AlertTriangle className="w-5 h-5" /> Emergency Mode
              </button>
            </div>
          </div>
        </>
      )}

      {/* Bottom Nav (Mobile/Sticky) */}
      {state.currentView !== 'interaction' && state.currentView !== 'emergency' && (
        <nav className="fixed bottom-6 left-1/2 -translate-x-1/2 bg-white/80 backdrop-blur-md border border-slate-200 px-6 py-3 rounded-2xl shadow-xl flex items-center gap-8 z-20">
          <button 
            onClick={() => setState({ ...state, currentView: 'home' })}
            className={`flex flex-col items-center gap-1 transition-colors ${state.currentView === 'home' ? 'text-emerald-500' : 'text-slate-400 hover:text-slate-600'}`}
          >
            <HomeIcon className="w-5 h-5" />
            <span className="text-[10px] font-bold">Home</span>
          </button>
          <button 
            onClick={() => setState({ ...state, currentView: 'tracker' })}
            className={`flex flex-col items-center gap-1 transition-colors ${state.currentView === 'tracker' ? 'text-emerald-500' : 'text-slate-400 hover:text-slate-600'}`}
          >
            <Clock className="w-5 h-5" />
            <span className="text-[10px] font-bold">Tracker</span>
          </button>
          <button 
            onClick={() => setState({ ...state, currentView: 'glossary' })}
            className={`flex flex-col items-center gap-1 transition-colors ${state.currentView === 'glossary' ? 'text-emerald-500' : 'text-slate-400 hover:text-slate-600'}`}
          >
            <BookOpen className="w-5 h-5" />
            <span className="text-[10px] font-bold">Glossary</span>
          </button>
        </nav>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
/* Added missing Scale icon import */
import { Shield, Search, Mic, Home as HomeIcon, BookOpen, Clock, AlertTriangle, Menu, X, ArrowLeft, Send, CheckCircle, ExternalLink, Scale } from 'lucide-react';
import { AppState, SavedCase, LegalAdvice, Category, ClarificationQuestion } from './types';
import { CATEGORIES, GLOSSARY } from './constants';
import { analyzeSituation } from './services/geminiService';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>({
    currentView: 'home',
    history: [],
    isSearching: false
  });
  const [input, setInput] = useState('');
  const [advice, setAdvice] = useState<LegalAdvice | null>(null);
  const [clarification, setClarification] = useState<ClarificationQuestion | null>(null);
  const [savedCases, setSavedCases] = useState<SavedCase[]>([]);
  const [isRecording, setIsRecording] = useState(false);
  const [isMenuOpen, setIsMenuOpen] = useState(false);

  // Load saved cases from localStorage
  useEffect(() => {
    const stored = localStorage.getItem('naija_legal_cases');
    if (stored) {
      setSavedCases(JSON.parse(stored));
    }
  }, []);

  const saveCase = (advice: LegalAdvice, title: string) => {
    const newCase: SavedCase = {
      id: Date.now().toString(),
      title,
      timestamp: Date.now(),
      advice,
      status: 'pending'
    };
    const updated = [newCase, ...savedCases];
    setSavedCases(updated);
    localStorage.setItem('naija_legal_cases', JSON.stringify(updated));
    alert('Case saved to your tracker!');
  };

  const handleSearch = async (query: string = input) => {
    if (!query.trim()) return;
    setState(prev => ({ ...prev, isSearching: true, currentView: 'interaction' }));
    setAdvice(null);
    setClarification(null);

    try {
      const result = await analyzeSituation(query, state.history);
      if (result.needsClarification) {
        setClarification(result.needsClarification);
      } else if (result.advice) {
        setAdvice(result.advice);
      }
      setState(prev => ({ ...prev, history: [...prev.history, query], isSearching: false }));
    } catch (err) {
      alert("Something went wrong. Please check your internet connection.");
      setState(prev => ({ ...prev, isSearching: false, currentView: 'home' }));
    }
  };

  const handleClarification = (option: string) => {
    handleSearch(`${clarification?.question}: ${option}`);
  };

  const handleVoice = () => {
    if (!('webkitSpeechRecognition' in window)) {
      alert("Speech recognition not supported in this browser.");
      return;
    }
    const recognition = new (window as any).webkitSpeechRecognition();
    recognition.lang = 'en-NG';
    recognition.onstart = () => setIsRecording(true);
    recognition.onresult = (event: any) => {
      const transcript = event.results[0][0].transcript;
      setInput(transcript);
      handleSearch(transcript);
    };
    recognition.onend = () => setIsRecording(false);
    recognition.start();
  };

  const renderHome = () => (
    <div className="max-w-2xl mx-auto px-4 py-8">
      <div className="text-center mb-10">
        <h1 className="text-3xl font-bold text-slate-800 mb-2">How can I help you today?</h1>
        <p className="text-slate-500">Get clear legal guidance on Nigerian laws in seconds.</p>
      </div>

      <div className="relative mb-8 group">
        <div className="absolute inset-y-0 left-4 flex items-center pointer-events-none">
          <Search className="w-5 h-5 text-slate-400" />
        </div>
        <input
          type="text"
          value={input}
          onChange={(e) => setInput(e.target.value)}
          placeholder="Type your situation (e.g. My landlord cut my light)"
          className="w-full pl-12 pr-12 py-4 bg-white border border-slate-200 rounded-2xl shadow-sm focus:ring-2 focus:ring-emerald-500 focus:border-transparent outline-none transition-all"
          onKeyDown={(e) => e.key === 'Enter' && handleSearch()}
        />
        <button 
          onClick={handleVoice}
          className={`absolute inset-y-0 right-4 flex items-center transition-colors ${isRecording ? 'text-red-500 animate-pulse' : 'text-slate-400 hover:text-emerald-500'}`}
        >
          <Mic className="w-5 h-5" />
        </button>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-3 gap-4 mb-10">
        {CATEGORIES.map((cat) => (
          <button
            key={cat.id}
            onClick={() => handleSearch(cat.name)}
            className="flex flex-col items-center justify-center p-4 bg-white border border-slate-100 rounded-2xl shadow-sm hover:shadow-md hover:border-emerald-200 transition-all group"
          >
            <div className={`p-3 rounded-full mb-3 ${cat.color} group-hover:scale-110 transition-transform`}>
              {cat.icon}
            </div>
            <span className="text-xs font-semibold text-slate-700 text-center">{cat.name}</span>
          </button>
        ))}
      </div>

      <div className="bg-emerald-50 rounded-2xl p-6 border border-emerald-100 flex items-start gap-4">
        <div className="bg-emerald-500 p-2 rounded-lg text-white">
          <AlertTriangle className="w-5 h-5" />
        </div>
        <div>
          <h3 className="font-semibold text-emerald-900 mb-1 text-sm">Emergency?</h3>
          <p className="text-emerald-700 text-xs leading-relaxed">
            If you are currently being detained or facing immediate danger, tap Emergency Mode for instant safety steps.
          </p>
          <button 
            onClick={() => setState({ ...state, currentView: 'emergency' })}
            className="mt-2 text-emerald-800 font-bold text-xs uppercase tracking-wider"
          >
            Go to Emergency Mode &rarr;
          </button>
        </div>
      </div>
    </div>
  );

  const renderInteraction = () => (
    <div className="max-w-2xl mx-auto px-4 py-8">
      <button 
        onClick={() => setState({ ...state, currentView: 'home' })}
        className="flex items-center text-slate-500 hover:text-slate-800 mb-6 transition-colors"
      >
        <ArrowLeft className="w-4 h-4 mr-2" /> Back
      </button>

      {state.isSearching ? (
        <div className="flex flex-col items-center justify-center py-20 space-y-4">
          <div className="w-12 h-12 border-4 border-emerald-500 border-t-transparent rounded-full animate-spin"></div>
          <p className="text-slate-600 font-medium animate-pulse text-center">
            Reviewing Nigerian Law Books... <br/>
            <span className="text-xs text-slate-400">Verifying the most current regulations</span>
          </p>
        </div>
      ) : clarification ? (
        <div className="bg-white rounded-2xl p-8 shadow-sm border border-slate-100 animate-in slide-in-from-bottom-4 duration-300">
          <h2 className="text-xl font-bold text-slate-800 mb-6">{clarification.question}</h2>
          <div className="space-y-3">
            {clarification.options.map((option, idx) => (
              <button
                key={idx}
                onClick={() => handleClarification(option)}
                className="w-full text-left p-4 rounded-xl border border-slate-200 hover:border-emerald-500 hover:bg-emerald-50 transition-all font-medium text-slate-700"
              >
                {option}
              </button>
            ))}
          </div>
        </div>
      ) : advice ? (
        <div className="space-y-6 pb-20 animate-in fade-in duration-500">
          <div className="bg-emerald-600 text-white rounded-2xl p-6 shadow-lg">
            <h2 className="text-lg font-bold mb-3 flex items-center">
              <CheckCircle className="w-5 h-5 mr-2" />
              Here's the Guidance
            </h2>
            <p className="text-emerald-50 leading-relaxed text-sm">
              {advice.explanation}
            </p>
          </div>

          <div className="bg-white rounded-2xl p-6 border border-slate-200 shadow-sm">
            <h3 className="font-bold text-slate-800 mb-4 flex items-center">
              <Clock className="w-4 h-4 mr-2 text-blue-500" />
              Steps You Should Take
            </h3>
            <ul className="space-y-4">
              {advice.steps.map((step, i) => (
                <li key={i} className="flex gap-4">
                  <div className="flex-shrink-0 w-6 h-6 rounded-full bg-slate-100 text-slate-600 text-xs flex items-center justify-center font-bold">
                    {i + 1}
                  </div>
                  <span className="text-slate-600 text-sm">{step}</span>
                </li>
              ))}
            </ul>
          </div>

          <div className="bg-white rounded-2xl p-6 border border-slate-200 shadow-sm">
            <h3 className="font-bold text-slate-800 mb-4 flex items-center">
              <Scale className="w-4 h-4 mr-2 text-indigo-500" />
              Legal References (Nigeria)
            </h3>
            <div className="space-y-3">
              {advice.laws.map((law, i) => (
                <div key={i} className="p-3 bg-slate-50 rounded-xl border border-slate-100">
                  <p className="font-semibold text-slate-800 text-sm">{law.title}</p>
                  <p className="text-xs text-slate-500">{law.section}</p>
                </div>
              ))}
            </div>
          </div>

          {advice.templates && advice.templates.length > 0 && (
            <div className="bg-white rounded-2xl p-6 border border-slate-200 shadow-sm">
              <h3 className="font-bold text-slate-800 mb-4 flex items-center">
                <Send className="w-4 h-4 mr-2 text-emerald-500" />
                Templates & Forms
              </h3>
              <div className="space-y-3">
                {advice.templates.map((tmpl, i) => (
                  <button 
                    key={i}
                    onClick={() => {
                      navigator.clipboard.writeText(tmpl.content);
                      alert('Template copied to clipboard!');
                    }}
                    className="w-full text-left p-3 rounded-xl bg-emerald-50 text-emerald-700 border border-emerald-100 flex items-center justify-between hover:bg-emerald-100 transition-all"
                  >
                    <span className="text-sm font-medium">{tmpl.name}</span>
                    <span className="text-[10px] bg-white px-2 py-1 rounded-full uppercase font-bold border border-emerald-200">Copy</span>
                  </button>
                ))}
              </div>
            </div>
          )}

          {advice.groundingUrls && advice.groundingUrls.length > 0 && (
            <div className="p-4 bg-slate-100 rounded-xl text-xs">
              <p className="text-slate-500 mb-2 font-bold uppercase tracking-tight">Verified Sources:</p>
              <div className="flex flex-wrap gap-2">
                {advice.groundingUrls.map((url, i) => (
                  <a key={i} href={url} target="_blank" rel="noopener noreferrer" className="text-emerald-600 hover:underline flex items-center gap-1">
                    Source {i + 1} <ExternalLink className="w-2 h-2" />
                  </a>
                ))}
              </div>
            </div>
          )}

          <div className="fixed bottom-6 left-0 right-0 px-4 flex gap-3 max-w-2xl mx-auto">
            <button 
              onClick={() => saveCase(advice, input || "Saved Advice")}
              className="flex-1 bg-white border border-slate-200 text-slate-700 font-bold py-3 rounded-xl shadow-lg flex items-center justify-center gap-2 hover:bg-slate-50 transition-all"
            >
              <Clock className="w-4 h-4" /> Save to Tracker
            </button>
            <button 
              onClick={() => setState({ ...state, currentView: 'home' })}
              className="bg-emerald-500 text-white font-bold py-3 px-8 rounded-xl shadow-lg hover:bg-emerald-600 transition-all"
            >
              Done
            </button>
          </div>
        </div>
      ) : null}
    </div>
  );

  const renderTracker = () => (
    <div className="max-w-2xl mx-auto px-4 py-8 pb-24">
      <h2 className="text-2xl font-bold text-slate-800 mb-6 flex items-center">
        <Clock className="w-6 h-6 mr-3 text-blue-500" /> Case Tracker
      </h2>
      {savedCases.length === 0 ? (
        <div className="text-center py-20 bg-white rounded-2xl border border-dashed border-slate-200">
          <p className="text-slate-400">No saved cases yet.</p>
        </div>
      ) : (
        <div className="space-y-4">
          {savedCases.map((c) => (
            <div key={c.id} className="bg-white p-5 rounded-2xl border border-slate-200 shadow-sm hover:border-emerald-200 transition-all">
              <div className="flex justify-between items-start mb-2">
                <h3 className="font-bold text-slate-800">{c.title}</h3>
                <span className={`text-[10px] px-2 py-1 rounded-full uppercase font-bold ${
                  c.status === 'resolved' ? 'bg-emerald-100 text-emerald-700' : 'bg-orange-100 text-orange-700'
                }`}>
                  {c.status}
                </span>
              </div>
              <p className="text-xs text-slate-400 mb-4">{new Date(c.timestamp).toLocaleDateString()}</p>
              <button 
                onClick={() => {
                  setAdvice(c.advice);
                  setState({ ...state, currentView: 'interaction' });
                }}
                className="text-emerald-600 text-sm font-bold hover:underline"
              >
                View Advice &rarr;
              </button>
            </div>
          ))}
        </div>
      )}
    </div>
  );

  const renderGlossary = () => (
    <div className="max-w-2xl mx-auto px-4 py-8 pb-24">
      <h2 className="text-2xl font-bold text-slate-800 mb-6 flex items-center">
        <BookOpen className="w-6 h-6 mr-3 text-indigo-500" /> Legal Glossary
      </h2>
      <div className="space-y-4">
        {GLOSSARY.map((item, i) => (
          <div key={i} className="bg-white p-5 rounded-2xl border border-slate-200 shadow-sm">
            <h3 className="font-bold text-emerald-600 mb-1">{item.term}</h3>
            <p className="text-slate-600 text-sm leading-relaxed">{item.definition}</p>
          </div>
        ))}
      </div>
    </div>
  );

  const renderEmergency = () => (
    <div className="max-w-2xl mx-auto px-4 py-8 bg-red-50 min-h-screen">
      <button 
        onClick={() => setState({ ...state, currentView: 'home' })}
        className="flex items-center text-red-600 font-bold mb-6"
      >
        <ArrowLeft className="w-4 h-4 mr-2" /> Exit Emergency Mode
      </button>

      <div className="bg-red-600 text-white rounded-2xl p-8 shadow-xl mb-6">
        <div className="flex items-center gap-4 mb-4">
          <AlertTriangle className="w-10 h-10 animate-pulse" />
          <h2 className="text-3xl font-extrabold uppercase tracking-tight">Emergency Steps</h2>
        </div>
        <p className="font-medium text-red-100 mb-6">If you are currently facing legal trouble, follow these steps immediately:</p>

        <div className="space-y-6">
          <div className="bg-red-700/50 p-4 rounded-xl">
            <h4 className="font-bold mb-1">1. Stay Calm & Compliant</h4>
            <p className="text-sm text-red-100">Do not resist physically. Maintain a respectful but firm tone.</p>
          </div>
          <div className="bg-red-700/50 p-4 rounded-xl">
            <h4 className="font-bold mb-1">2. Identify Yourself</h4>
            <p className="text-sm text-red-100">You are required to show ID. You are NOT required to give passwords to your phone without a warrant.</p>
          </div>
          <div className="bg-red-700/50 p-4 rounded-xl">
            <h4 className="font-bold mb-1">3. Record and Recall</h4>
            <p className="text-sm text-red-100">Take note of officer names, badge numbers, vehicle plates, and location if possible.</p>
          </div>
          <div className="bg-red-700/50 p-4 rounded-xl">
            <h4 className="font-bold mb-1">4. Contact Legal Aid</h4>
            <p className="text-sm text-red-100">Call the Legal Aid Council of Nigeria at +234 800 000 0000 or your family lawyer.</p>
          </div>
        </div>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-30 px-4 py-3 shadow-sm">
        <div className="max-w-2xl mx-auto flex justify-between items-center">
          <div 
            className="flex items-center gap-2 cursor-pointer"
            onClick={() => setState({ ...state, currentView: 'home' })}
          >
            <div className="bg-emerald-500 p-1.5 rounded-lg text-white">
              <Shield className="w-6 h-6" />
            </div>
            <span className="font-bold text-slate-800 tracking-tight">Naija Legal Buddy</span>
          </div>
          <button 
            onClick={() => setIsMenuOpen(!isMenuOpen)}
            className="p-2 text-slate-500 hover:bg-slate-50 rounded-lg transition-colors"
          >
            {isMenuOpen ? <X /> : <Menu />}
          </button>
        </div>
      </header>

      {/* Main Content Area */}
      <main className="flex-grow">
        {state.currentView === 'home' && renderHome()}
        {state.currentView === 'interaction' && renderInteraction()}
        {state.currentView === 'tracker' && renderTracker()}
        {state.currentView === 'glossary' && renderGlossary()}
        {state.currentView === 'emergency' && renderEmergency()}
      </main>

      {/* Side Menu Drawer */}
      {isMenuOpen && (
        <>
          <div className="fixed inset-0 bg-black/20 z-40 backdrop-blur-sm" onClick={() => setIsMenuOpen(false)}></div>
          <div className="fixed top-0 right-0 h-full w-64 bg-white z-50 shadow-2xl p-6 animate-in slide-in-from-right duration-300">
            <button onClick={() => setIsMenuOpen(false)} className="absolute top-4 right-4 text-slate-400"><X /></button>
            <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-6">Menu</h3>
            <div className="space-y-2">
              <button 
                onClick={() => { setState({ ...state, currentView: 'home' }); setIsMenuOpen(false); }}
                className="w-full flex items-center gap-3 p-3 rounded-xl hover:bg-slate-50 text-slate-700 font-medium transition-colors"
              >
                <HomeIcon className="w-5 h-5 text-emerald-500" /> Home
              </button>
              <button 
                onClick={() => { setState({ ...state, currentView: 'tracker' }); setIsMenuOpen(false); }}
                className="w-full flex items-center gap-3 p-3 rounded-xl hover:bg-slate-50 text-slate-700 font-medium transition-colors"
              >
                <Clock className="w-5 h-5 text-blue-500" /> Case Tracker
              </button>
              <button 
                onClick={() => { setState({ ...state, currentView: 'glossary' }); setIsMenuOpen(false); }}
                className="w-full flex items-center gap-3 p-3 rounded-xl hover:bg-slate-50 text-slate-700 font-medium transition-colors"
              >
                <BookOpen className="w-5 h-5 text-indigo-500" /> Legal Glossary
              </button>
              <button 
                onClick={() => { setState({ ...state, currentView: 'emergency' }); setIsMenuOpen(false); }}
                className="w-full flex items-center gap-3 p-3 rounded-xl hover:bg-red-50 text-red-600 font-bold transition-colors"
              >
                <AlertTriangle className="w-5 h-5" /> Emergency Mode
              </button>
            </div>
          </div>
        </>
      )}

      {/* Bottom Nav (Mobile/Sticky) */}
      {state.currentView !== 'interaction' && state.currentView !== 'emergency' && (
        <nav className="fixed bottom-6 left-1/2 -translate-x-1/2 bg-white/80 backdrop-blur-md border border-slate-200 px-6 py-3 rounded-2xl shadow-xl flex items-center gap-8 z-20">
          <button 
            onClick={() => setState({ ...state, currentView: 'home' })}
            className={`flex flex-col items-center gap-1 transition-colors ${state.currentView === 'home' ? 'text-emerald-500' : 'text-slate-400 hover:text-slate-600'}`}
          >
            <HomeIcon className="w-5 h-5" />
            <span className="text-[10px] font-bold">Home</span>
          </button>
          <button 
            onClick={() => setState({ ...state, currentView: 'tracker' })}
            className={`flex flex-col items-center gap-1 transition-colors ${state.currentView === 'tracker' ? 'text-emerald-500' : 'text-slate-400 hover:text-slate-600'}`}
          >
            <Clock className="w-5 h-5" />
            <span className="text-[10px] font-bold">Tracker</span>
          </button>
          <button 
            onClick={() => setState({ ...state, currentView: 'glossary' })}
            className={`flex flex-col items-center gap-1 transition-colors ${state.currentView === 'glossary' ? 'text-emerald-500' : 'text-slate-400 hover:text-slate-600'}`}
          >
            <BookOpen className="w-5 h-5" />
            <span className="text-[10px] font-bold">Glossary</span>
          </button>
        </nav>
      )}
    </div>
  );
};

export default App;

export enum Category {
  TRAFFIC = 'Traffic / Police Stops',
  LANDLORD = 'Landlord / Tenant Issues',
  WORKPLACE = 'Workplace & Salary Rights',
  CONSUMER = 'Consumer Rights / Fraud',
  DOMESTIC = 'Domestic Disputes',
  EMERGENCY = 'Emergency Situations'
}

export type Language = 'English' | 'Pidgin' | 'Yoruba' | 'Igbo' | 'Hausa';

export interface LegalAdvice {
  explanation: string;
  steps: string[];
  laws: { title: string; section: string; link?: string }[];
  templates?: { name: string; content: string }[];
  contacts?: { name: string; info: string }[];
  groundingUrls?: string[];
}

export interface ClarificationQuestion {
  question: string;
  options: string[];
}

export interface DocumentTemplate {
  id: string;
  name: string;
  description: string;
  category: string;
  content: string; // Markdown or raw text with placeholders like {{name}}
  fields: string[]; // List of placeholder keys
}

export interface SavedCase {
  id: string;
  title: string;
  timestamp: number;
  advice: LegalAdvice;
  status: 'pending' | 'resolved' | 'sent';
